package wallet_test

import (
	"encoding/hex"

	"github.com/bsv-blockchain/go-sdk/overlay/lookup"
	sdk "github.com/bsv-blockchain/go-sdk/wallet"
	"github.com/stretchr/testify/require"

	"github.com/bsv-blockchain/go-wallet-toolbox/pkg/internal/fixtures"
	"github.com/bsv-blockchain/go-wallet-toolbox/pkg/internal/fixtures/testusers"
	"github.com/bsv-blockchain/go-wallet-toolbox/pkg/wallet"
	"github.com/bsv-blockchain/go-wallet-toolbox/pkg/wallet/internal/testabilities"
)

func (s *WalletTestSuite) TestDiscoverByIdentityKey() {
	t := s.T()

	s.Run("empty results - should return empty result when no certificates found", func() {
		// given:
		given, cleanup := testabilities.Given(t)
		defer cleanup()

		// and:
		mockResolver := given.MockLookupResolver(&lookup.LookupAnswer{
			Type:    lookup.AnswerTypeOutputList,
			Outputs: []*lookup.OutputListItem{},
		}, nil)

		// and:
		aliceWallet := given.Wallet().
			WithActiveStorage(s.StorageType).
			WithWalletOpts(wallet.WithLookupResolver(mockResolver)).
			ForUser(testusers.Alice)

		// and:
		bobWallet := given.BobWalletWithStorage(s.StorageType)
		bobKey, err := bobWallet.GetPublicKey(t.Context(), sdk.GetPublicKeyArgs{IdentityKey: true}, fixtures.DefaultOriginator)
		require.NoError(t, err)
		require.NotNil(t, bobKey)

		// when:
		result, err := aliceWallet.DiscoverByIdentityKey(t.Context(), sdk.DiscoverByIdentityKeyArgs{
			IdentityKey: bobKey.PublicKey,
		}, fixtures.DefaultOriginator)

		// then:
		require.NoError(t, err)
		require.NotNil(t, result)
		require.Equal(t, uint32(0), result.TotalCertificates)
		require.Empty(t, result.Certificates)
	})

	s.Run("success - should discover certificates for valid identity key", func() {
		given, cleanup := testabilities.Given(t)
		defer cleanup()

		// and:
		beefHexWithCert := ""
		beef, err := hex.DecodeString(beefHexWithCert)
		require.NoError(t, err, "Failed to decode BEEF hex data")
		mockResolver := given.MockLookupResolver(&lookup.LookupAnswer{
			Type: lookup.AnswerTypeOutputList,
			Outputs: []*lookup.OutputListItem{{
				Beef:        beef,
				OutputIndex: 0,
			}},
		}, nil)

		// and:
		aliceWallet := given.Wallet().
			WithActiveStorage(s.StorageType).
			WithWalletOpts(wallet.WithLookupResolver(mockResolver)).
			ForUser(testusers.Alice)

		// when:
		result, err := aliceWallet.DiscoverByIdentityKey(t.Context(), sdk.DiscoverByIdentityKeyArgs{
			IdentityKey: testusers.Bob.PublicKey(t),
		}, fixtures.DefaultOriginator)

		// then:
		require.NoError(t, err)
		require.NotNil(t, result)
		require.Equal(t, uint32(1), result.TotalCertificates)
		require.NotEmpty(t, result.Certificates)
	})
}
